import { type, fn } from "arktype";

// ---------------------------------------------------------------------------
// State – discriminated union on `status`
// ---------------------------------------------------------------------------

export const Idle = type({
  status: "'idle'",
});

export const Loading = type({
  status: "'loading'",
  startedAt: "number.integer >= 0",
});

export const Success = type({
  status: "'success'",
  data: "unknown",
  fetchedAt: "number.integer >= 0",
});

export const Failure = type({
  status: "'failure'",
  // inclusive range [400, 599]
  code: "number.integer >= 400 & number.integer <= 599",
  // length 1..200
  reason: "1 <= string <= 200",
});

export const State = Idle.or(Loading).or(Success).or(Failure);
export type State = typeof State.infer;

// ---------------------------------------------------------------------------
// Event – discriminated union on `type`
// ---------------------------------------------------------------------------

export const StartEvent = type({
  type: "'start'",
  at: "number",
});

export const ResolveEvent = type({
  type: "'resolve'",
  data: "unknown",
  at: "number",
});

export const RejectEvent = type({
  type: "'reject'",
  code: "number.integer",
  reason: "string",
  at: "number",
});

export const ResetEvent = type({
  type: "'reset'",
});

export const Event = StartEvent.or(ResolveEvent).or(RejectEvent).or(ResetEvent);
export type Event = typeof Event.infer;

// ---------------------------------------------------------------------------
// Validated transition function
// ---------------------------------------------------------------------------

/**
 * Runtime-validated state-machine transition.
 *
 * Both parameters are checked against their respective union types, and the
 * return value is checked against `State` before being handed back to the
 * caller.  Any violation throws an `ArkErrors`-style error.
 */
export const transition = fn(State, Event, ":", State)(
  (state, event): State => {
    // Any state + Reset -> Idle
    if (event.type === "reset") {
      return { status: "idle" };
    }

    // Idle + Start -> Loading
    if (state.status === "idle" && event.type === "start") {
      return {
        status: "loading",
        startedAt: Math.trunc(event.at),
      };
    }

    // Loading + Resolve -> Success
    if (state.status === "loading" && event.type === "resolve") {
      return {
        status: "success",
        data: event.data,
        fetchedAt: Math.trunc(event.at),
      };
    }

    // Loading + Reject -> Failure
    if (state.status === "loading" && event.type === "reject") {
      return {
        status: "failure",
        code: event.code,
        reason: event.reason,
      };
    }

    // All other combinations: leave state unchanged
    return state;
  },
);

import { ArkErrors } from "arktype";
import { State, Event, transition } from "./src/types.js";

// ---------------------------------------------------------------------------
// Read stdin to completion
// ---------------------------------------------------------------------------

async function readStdin(): Promise<string> {
  const chunks: Buffer[] = [];
  for await (const chunk of process.stdin) {
    chunks.push(chunk as Buffer);
  }
  return Buffer.concat(chunks).toString("utf8");
}

// ---------------------------------------------------------------------------
// Main
// ---------------------------------------------------------------------------

async function main(): Promise<void> {
  const raw = await readStdin();

  // Parse the outer JSON envelope
  let envelope: unknown;
  try {
    envelope = JSON.parse(raw);
  } catch (err) {
    process.stdout.write(
      `INVALID: failed to parse JSON input: ${(err as Error).message}\n`,
    );
    process.exit(0);
  }

  // Basic shape check before destructuring
  if (
    typeof envelope !== "object" ||
    envelope === null ||
    !("initial" in envelope) ||
    !("events" in envelope) ||
    !Array.isArray((envelope as { events: unknown }).events)
  ) {
    process.stdout.write(
      `INVALID: input must be an object with "initial" (State) and "events" (array) fields\n`,
    );
    process.exit(0);
  }

  const { initial, events } = envelope as { initial: unknown; events: unknown[] };

  // Validate the initial state
  const initialResult = State(initial);
  if (initialResult instanceof ArkErrors) {
    process.stdout.write(`INVALID: initial state is invalid – ${initialResult.summary}\n`);
    process.exit(0);
  }

  // Replay events through the validated transition function
  let current: typeof State.infer = initialResult;

  for (let i = 0; i < events.length; i++) {
    const rawEvent = events[i];

    // Validate the event itself before passing to transition
    const eventResult = Event(rawEvent);
    if (eventResult instanceof ArkErrors) {
      process.stdout.write(
        `INVALID: event at index ${i} is invalid – ${eventResult.summary}\n`,
      );
      process.exit(0);
    }

    // Call the validated transition function; it also validates the return value
    try {
      current = transition(current, eventResult);
    } catch (err) {
      // ArkErrors thrown when the return value doesn't match State
      const summary =
        err instanceof ArkErrors ? err.summary : String(err);
      process.stdout.write(
        `INVALID: transition produced an invalid state at event index ${i} – ${summary}\n`,
      );
      process.exit(0);
    }
  }

  // All good – emit the final state
  process.stdout.write(`VALID\n${JSON.stringify(current)}\n`);
  process.exit(0);
}

main();

